B.KO=new A.bW("q3","business_admin","\uacbd\uc601\ud559","SWOT \ubd84\uc11d\uc5d0\uc11c \uae30\uc5c5 \ub0b4\ubd80 \uc5ed\ub7c9\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc744 \ubaa8\ub450 \uace0\ub974\uba74?",B.Fv,0,"SWOT \ubd84\uc11d\uc740 \uae30\uc5c5\uc758 \uacbd\uc601\ud658\uacbd\uc744 \ub0b4\ubd80 \uc694\uc778\uacfc \uc678\ubd80 \uc694\uc778\uc73c\ub85c \ub098\ub204\uc5b4 \ubd84\uc11d\ud558\ub294 \ub300\ud45c\uc801\uc778 \uc804\ub7b5 \uc218\ub9bd \ub3c4\uad6c\uc774\ub2e4. \uc774 \uc911 \uac15\uc810(Strength)\uacfc \uc57d\uc810(Weakness)\uc740 \uae30\uc5c5\uc774 \ud1b5\uc81c\ud560 \uc218 \uc788\ub294 \ub0b4\ubd80 \uc5ed\ub7c9(\uc790\uae08\ub825, \uae30\uc220\ub825, \uc870\uc9c1\ubb38\ud654, \ube0c\ub79c\ub4dc \ub4f1)\uc744 \ud3c9\uac00\ud55c \uac83\uc774\uace0, \uae30\ud68c(Opportunity)\uc640 \uc704\ud611(Threat)\uc740 \uae30\uc5c5\uc774 \ud1b5\uc81c\ud558\uae30 \uc5b4\ub824\uc6b4 \uc678\ubd80 \ud658\uacbd(\uc2dc\uc7a5 \uc131\uc7a5\ub960, \uacbd\uc7c1 \uac15\ub3c4, \uaddc\uc81c, \uac70\uc2dc\uacbd\uc81c \ub4f1)\uc744 \ud3c9\uac00\ud55c \uac83\uc774\ub2e4. \ub530\ub77c\uc11c \ub0b4\ubd80 \uc5ed\ub7c9\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc740 \uac15\uc810\uacfc \uc57d\uc810\uc774\uba70, \uc774\ub97c \ubc14\ud0d5\uc73c\ub85c SO(\uac15\uc810-\uae30\ud68c) \uc804\ub7b5, WT(\uc57d\uc810-\uc704\ud611) \uc804\ub7b5\ucc98\ub7fc \ub0b4\ubd80-\uc678\ubd80 \uc694\uc778\uc744 \uad50\ucc28 \ubd84\uc11d\ud558\uc5ec \uc804\ub7b5\uc744 \ub3c4\ucd9c\ud558\ub294 \uac83\uc774 SWOT \ubd84\uc11d\uc758 \ud575\uc2ec\uc774\ub2e4.",B.Ep,B.EA,"2025")
